    11→// SummaryComputer handles KB summary computation and promotion logic
    12→type SummaryComputer struct {
    13→	storage KBStorage
    14→	lockMgr KBLockManager
    15→	config  *SummaryConfig
    16→}
    17→
    18→// SummaryConfig contains configuration for summary computation
    19→type SummaryConfig struct {
    20→	MinCasesForPromotion  int     // Minimum cases needed to promote a fix
    21→	MinSuccessRate        float64 // Minimum success rate for promotion
    22→	MaxPromotedFixes      int     // Maximum fixes to keep in promoted list
    23→	RecencyWeight         float64 // Weight for recent successes (0.0-1.0)
    24→	FrequencyWeight       float64 // Weight for frequency (0.0-1.0)
    25→	SuccessRateWeight     float64 // Weight for success rate (0.0-1.0)
    26→	MinScore              float64 // Minimum score threshold for promotion
    27→	PromotionLookbackDays int     // Days to look back for recency scoring
    28→}
    29→
    30→// DefaultSummaryConfig returns reasonable defaults for summary computation
    31→func DefaultSummaryConfig() *SummaryConfig {
    32→	return &SummaryConfig{
    33→		MinCasesForPromotion:  3,
    34→		MinSuccessRate:        0.6,
    35→		MaxPromotedFixes:      10,
    36→		RecencyWeight:         0.3,
    37→		FrequencyWeight:       0.4,
    38→		SuccessRateWeight:     0.3,
    39→		MinScore:              0.5,
    40→		PromotionLookbackDays: 90,
    41→	}
    42→}
