    44→// NewSummaryComputer creates a new summary computer
    45→func NewSummaryComputer(storage KBStorage, lockMgr KBLockManager, config *SummaryConfig) *SummaryComputer {
    46→	if config == nil {
    47→		config = DefaultSummaryConfig()
    48→	}
    49→	return &SummaryComputer{
    50→		storage: storage,
    51→		lockMgr: lockMgr,
    52→		config:  config,
    53→	}
    54→}
