    56→// FixCandidate represents a potential fix for promotion
    57→type FixCandidate struct {
    58→	Kind          string
    59→	Ref           string
    60→	Wins          int
    61→	Failures      int
    62→	TotalCases    int
    63→	SuccessRate   float64
    64→	LastSuccessAt time.Time
    65→	FirstSeenAt   time.Time
    66→	Score         float64
    67→}
