   121→// analyzeCases examines cases to identify potential fixes
   122→func (sc *SummaryComputer) analyzeCases(cases []*CaseRecord) map[string]*FixCandidate {
   123→	candidates := make(map[string]*FixCandidate)
   124→
   125→	for _, caseRecord := range cases {
   126→		if caseRecord.Attempt == nil || caseRecord.Outcome == nil {
   127→			continue
   128→		}
   129→
   130→		var key, kind, ref string
   131→
   132→		// Identify the fix type and reference
   133→		switch caseRecord.Attempt.Type {
   134→		case "orw_recipe":
   135→			if caseRecord.Attempt.Recipe != "" {
   136→				kind = "orw_recipe"
   137→				ref = caseRecord.Attempt.Recipe
   138→				key = "recipe:" + ref
   139→			}
   140→		case "llm_patch":
   141→			if caseRecord.Attempt.PatchFingerprint != "" {
   142→				kind = "patch_fingerprint"
   143→				ref = caseRecord.Attempt.PatchFingerprint
   144→				key = "patch:" + ref
   145→			}
   146→		case "human_step":
   147→			// Human steps are typically not promoted as they're manual
   148→			continue
   149→		}
   150→
   151→		if key == "" {
   152→			continue // Skip invalid attempts
   153→		}
   154→
   155→		// Get or create candidate
   156→		candidate, exists := candidates[key]
   157→		if !exists {
   158→			candidate = &FixCandidate{
   159→				Kind:        kind,
   160→				Ref:         ref,
   161→				FirstSeenAt: caseRecord.Timestamp,
   162→			}
   163→			candidates[key] = candidate
   164→		}
   165→
   166→		// Update candidate statistics
   167→		candidate.TotalCases++
   168→
   169→		if caseRecord.Outcome.Success {
   170→			candidate.Wins++
   171→			if candidate.LastSuccessAt.IsZero() || caseRecord.Timestamp.After(candidate.LastSuccessAt) {
   172→				candidate.LastSuccessAt = caseRecord.Timestamp
   173→			}
   174→		} else {
   175→			candidate.Failures++
   176→		}
   177→
   178→		// Track earliest sighting
   179→		if caseRecord.Timestamp.Before(candidate.FirstSeenAt) {
   180→			candidate.FirstSeenAt = caseRecord.Timestamp
   181→		}
   182→	}
   183→
   184→	// Compute success rates
   185→	for _, candidate := range candidates {
   186→		if candidate.TotalCases > 0 {
   187→			candidate.SuccessRate = float64(candidate.Wins) / float64(candidate.TotalCases)
   188→		}
   189→	}
   190→
   191→	return candidates
   192→}
