   194→// scoreCandidates assigns scores to fix candidates based on multiple factors
   195→func (sc *SummaryComputer) scoreCandidates(candidates map[string]*FixCandidate) []*FixCandidate {
   196→	now := time.Now()
   197→	lookbackTime := now.AddDate(0, 0, -sc.config.PromotionLookbackDays)
   198→
   199→	var scoredCandidates []*FixCandidate
   200→
   201→	for _, candidate := range candidates {
   202→		// Apply minimum thresholds
   203→		if candidate.TotalCases < sc.config.MinCasesForPromotion {
   204→			continue
   205→		}
   206→		if candidate.SuccessRate < sc.config.MinSuccessRate {
   207→			continue
   208→		}
   209→
   210→		// Calculate score components
   211→		successRateScore := candidate.SuccessRate
   212→
   213→		// Frequency score (normalized by total cases, capped at 1.0)
   214→		frequencyScore := math.Min(1.0, float64(candidate.Wins)/10.0)
   215→
   216→		// Recency score (based on last success time)
   217→		var recencyScore float64
   218→		if !candidate.LastSuccessAt.IsZero() {
   219→			if candidate.LastSuccessAt.After(lookbackTime) {
   220→				// More recent successes score higher
   221→				daysSinceSuccess := float64(now.Sub(candidate.LastSuccessAt).Hours()) / 24.0
   222→				lookbackDays := float64(sc.config.PromotionLookbackDays)
   223→				recencyScore = math.Max(0.0, (lookbackDays-daysSinceSuccess)/lookbackDays)
   224→			}
   225→		}
   226→
   227→		// Weighted composite score
   228→		candidate.Score = (sc.config.SuccessRateWeight * successRateScore) +
   229→			(sc.config.FrequencyWeight * frequencyScore) +
   230→			(sc.config.RecencyWeight * recencyScore)
   231→
   232→		// Apply minimum score threshold
   233→		if candidate.Score >= sc.config.MinScore {
   234→			scoredCandidates = append(scoredCandidates, candidate)
   235→		}
   236→	}
   237→
   238→	// Sort by score (highest first)
   239→	sort.Slice(scoredCandidates, func(i, j int) bool {
   240→		return scoredCandidates[i].Score > scoredCandidates[j].Score
   241→	})
   242→
   243→	return scoredCandidates
   244→}
