   330→// UpdateSummaryAfterCase is a convenience method to update summary after adding a new case
   331→func (sc *SummaryComputer) UpdateSummaryAfterCase(ctx context.Context, lang, signature string) error {
   332→	// Try to update summary, but don't fail the operation if locking fails
   333→	// The compactor job will rebuild summaries periodically anyway
   334→	lockKey := BuildSignatureLockKey(lang, signature)
   335→	lockConfig := DefaultLockConfig()
   336→	lockConfig.MaxRetries = 1 // Single attempt
   337→	lockConfig.DefaultTTL = 5 * time.Second
   338→
   339→	err := sc.lockMgr.TryWithLockRetry(ctx, lockKey, lockConfig, func() error {
   340→		return sc.computeAndUpdateSummaryLocked(ctx, lang, signature)
   341→	})
   342→
   343→	// If we can't acquire the lock, that's okay - just return success
   344→	// The compactor will rebuild this later
   345→	if err != nil && err.Error() == "lock already held by another session" {
   346→		return nil
   347→	}
   348→
   349→	return err
   350→}
